Question 2: Distance Calculations

2.1 Distance to National Border
Get the outer border for national border

us_border &lt;- states |&gt;
  st_union() |&gt;
  st_cast("MULTILINESTRING")


cities &lt;- cities |&gt;
  mutate(
    dist_to_border = st_distance(geometry, us_border),
    dist_to_border = set_units(dist_to_border, "km"),
    dist_to_border = drop_units(dist_to_border)
  )

Table 1. Top 5 Cities Farthest From National Border

farthest_border &lt;- cities |&gt;
  st_drop_geometry() |&gt;
  select(city, state_id, dist_to_border) |&gt;
  arrange(desc(dist_to_border)) |&gt;
  slice_head(n = 5)

flextable(farthest_border)

